What does this program print to stdout? (Assume input is `-5`.)

```cpp
#include <iostream>
#include <cstdlib>
int main() {
    int n{};
    std::cin >> n;
    if (n < 0) {
        std::cerr << "negative\n";
        std::exit(1);
    }
    std::cout << "value: " << n << "\n";
    return 0;
}
```

This program should print `Result: 5` when given inputs `10` and `2`, and exit with an error message if the divisor is 0. What is wrong?

```cpp
#include <iostream>
#include <cstdlib>
int main() {
    int a{}, b{};
    std::cin >> a >> b;
    if (b == 0) {
        std::cout << "Error: division by zero.\n";
        std::exit(EXIT_SUCCESS);
    }
    std::cout << "Result: " << a / b << "\n";
    return 0;
}
```
